// 화해 리뷰 랭킹 기반 실제 제품 데이터 (별점은 참고용 근사값).
// fullMl/price 는 카테고리 기준 근사값(수정 가능), oliveYoungUrl 은 제품명 검색 링크.
// image: 실제 제품 이미지 URL을 넣으면 노출, 비어 있으면 브랜드 컬러 플레이스홀더로 폴백.

import { allergyRiskForProduct } from "./allergens-data";
import productsRegistry from "../data/products.json";

// cosmetic_id → 전성분(전수, data/products.json) 조회 — 직접 입력한 알러지 자유 텍스트를
// 짧은 마케팅 성분 태그(Cosmetic.ingredients)뿐 아니라 전성분표까지 대조하기 위해 쓴다.
const INCI_BY_COSMETIC_ID: Record<string, string[]> = Object.fromEntries(
  (productsRegistry as { cosmetic_id: string; ingredients_inci: string[] }[]).map((e) => [e.cosmetic_id, e.ingredients_inci])
);
export function fullIngredientsFor(cosmeticId: string): string[] | undefined {
  return INCI_BY_COSMETIC_ID[cosmeticId];
}

export type Cosmetic = {
  id: string;
  brand: string;
  brandJp?: string; // 일본어 브랜드명 (언어 전환용, 없으면 brand로 폴백)
  brandEn?: string; // 영어 브랜드명 (언어 전환용, 없으면 brand로 폴백)
  name: string;
  nameJp?: string; // 일본어 제품명 (언어 전환용, 없으면 name으로 폴백)
  nameEn?: string; // 영어 제품명 (언어 전환용, 없으면 name으로 폴백)
  category: string; // 세럼/크림/토너/앰플/클렌징/선크림/마스크팩/로션
  ingredients: string[];
  forTypes: string[]; // 건성/지성/복합/중성/민감
  concerns: string[]; // 주름/기미/수분/트러블
  rating: number;
  feel: string; // 산뜻/보습/진정/촉촉
  desc: string;
  descJp?: string; // 일본어 설명 (언어 전환용, 없으면 desc로 폴백)
  descEn?: string; // 영어 설명 (언어 전환용, 없으면 desc로 폴백)
  fullMl: number; // 정품 용량
  price: number; // 정가(원, 근사·참고용)
  safety: string[]; // 약산성/무향/저자극/무기자차 등
  oliveYoungUrl: string;
  linkType: "direct" | "search"; // direct=개별 상품페이지, search=검색 폴백
  image?: string;
};

