export type WxProfile = { temp: number; humidity: number; uv: number; dust: number };
export type Recommendation = { p: Cosmetic; reason: string; reasonJp: string; reasonEn: string };

// 언어 전환(KO/JP/EN) — 추천 요약·이유 문장에 쓰이는 고정 어휘(유한 집합) 번역 사전
const SKINTYPE_TR: Record<string, { jp: string; en: string }> = {
  "건성": { jp: "乾燥肌", en: "dry skin" },
  "지성": { jp: "脂性肌", en: "oily skin" },
  "민감성": { jp: "敏感肌", en: "sensitive skin" },
};
const CONCERN_TR: Record<string, { jp: string; en: string }> = {
  "수분": { jp: "水分", en: "Hydration" },
  "트러블": { jp: "トラブル", en: "Blemishes" },
  "기미": { jp: "シミ", en: "Spots" },
  "주름": { jp: "シワ", en: "Wrinkles" },
};

export function normType(t: string) {
  return t.replace("복합성", "복합").replace("민감성", "민감");
}

export function recommendCosmetics(
  skinTypeForRec: string,
  sensitivity: string,
  concerns: string[],
  wx: WxProfile,
  userAllergies: string[] = []
): { summary: string; summaryJp: string; summaryEn: string; items: Recommendation[] } {
  const skin = normType(skinTypeForRec);
  const dry = wx.humidity <= 45;
  const hotHumid = wx.temp >= 30 && wx.humidity >= 70;
  const hiUV = wx.uv >= 8;
  const hiDust = wx.dust >= 80;

  // 등록된 알러지 성분과 겹치는 제품은 어떤 추천 목록에도 나오지 않도록 아예 제외한다.
  const scored = COSMETICS.filter((p) => allergyRiskForProduct(userAllergies, p.ingredients, p.safety, fullIngredientsFor(p.id)).length === 0).map((p) => {
    let s = 0;
    if (p.forTypes.includes(skin)) s += 3;
    const matched = concerns.filter((c) => p.concerns.includes(c));
    s += matched.length * 2;
    s += (p.rating - 4.3) * 4;
    if (sensitivity === "민감") {
      if (p.forTypes.includes("민감")) s += 1.5;
      if (p.feel === "진정") s += 1;
    }
    if (dry && p.concerns.includes("수분")) s += 2;
    if (hotHumid) {
      if (p.feel === "산뜻") s += 1.5;
      if (["클렌징", "토너", "선크림"].includes(p.category)) s += 0.6;
    }
    if (hiUV) {
      if (p.category === "선크림") s += 2.5;
      if (p.concerns.includes("기미")) s += 1;
    }
    if (hiDust && (p.concerns.includes("트러블") || p.category === "클렌징")) s += 1;
    return { p, s, matched };
  });

  scored.sort((a, b) => b.s - a.s || b.p.rating - a.p.rating);

  // 카테고리별로 가장 점수가 높은 제품 1개만 후보로 남긴다 — "카테고리별 대표" 추천이라는
  // 취지대로, 같은 카테고리(예: 토너 2개)가 중복으로 추천되지 않게 하고 클렌징폼처럼
  // 전체 경쟁에서 밀리기 쉬운 카테고리도 항상 하나는 포함되게 한다.
  const seenCategory = new Set<string>();
  const top = scored.filter(({ p }) => {
    if (seenCategory.has(p.category)) return false;
    seenCategory.add(p.category);
    return true;
  });

  const skinTr = SKINTYPE_TR[skinTypeForRec] ?? { jp: skinTypeForRec, en: skinTypeForRec };

  const items: Recommendation[] = top.map(({ p, matched }) => {
    const bits: string[] = [];
    const bitsJp: string[] = [];
    const bitsEn: string[] = [];
    if (p.forTypes.includes(skin)) {
      bits.push(`${skinTypeForRec} 피부 적합`);
      bitsJp.push(`${skinTr.jp}に適合`);
      bitsEn.push(`Great fit for ${skinTr.en}`);
    }
    if (p.ingredients[0]) {
      bits.push(`${p.ingredients[0]} 함유`);
      bitsJp.push(`${p.ingredients[0]}配合`);
      bitsEn.push(`Contains ${p.ingredients[0]}`);
    }
    if (hiUV && p.category === "선크림") {
      bits.push("강한 자외선 차단");
      bitsJp.push("強い紫外線カット");
      bitsEn.push("Strong UV protection");
    } else if (hiDust && p.category === "클렌징") {
      bits.push("미세먼지 많은 날 클렌징 케어");
      bitsJp.push("微細粉塵の多い日のクレンジングケア");
      bitsEn.push("Cleansing care for high-dust days");
    } else if (dry && p.concerns.includes("수분")) {
      bits.push("건조한 기후 속보습");
      bitsJp.push("乾燥した気候でのインナー保湿");
      bitsEn.push("Deep hydration for dry climates");
    } else if (hotHumid && p.feel === "산뜻") {
      bits.push("습한 날 산뜻하게");
      bitsJp.push("湿度が高い日もさっぱり");
      bitsEn.push("Refreshing on humid days");
    } else if (matched[0]) {
      const c = CONCERN_TR[matched[0]];
      bits.push(`'${matched[0]}' 고민 케어`);
      bitsJp.push(`「${c?.jp ?? matched[0]}」ケア`);
      bitsEn.push(`${c?.en ?? matched[0]} care`);
    }
    return {
      p,
      reason: bits.slice(0, 3).join(" · "),
      reasonJp: bitsJp.slice(0, 3).join(" · "),
      reasonEn: bitsEn.slice(0, 3).join(" · "),
    };
  });

  const driver = hiUV ? "강한 자외선" : dry ? "건조한 공기" : hotHumid ? "고온다습" : hiDust ? "높은 미세먼지" : "쾌적한 날씨";
  const driverJp = hiUV ? "強い紫外線" : dry ? "乾燥した空気" : hotHumid ? "高温多湿" : hiDust ? "高い微細粉塵" : "快適な天気";
  const driverEn = hiUV ? "strong UV" : dry ? "dry air" : hotHumid ? "hot and humid weather" : hiDust ? "high fine dust" : "pleasant weather";
  const approach =
    sensitivity === "민감"
      ? "진정 성분(센텔라·판테놀)"
      : skin === "건성"
        ? "고보습(히알루론산·세라마이드)"
        : skin === "지성"
          ? "피지 케어(BHA·나이아신)"
          : "수분·톤 밸런스";
  const approachJp =
    sensitivity === "민감"
      ? "鎮静成分（ツボクサ・パンテノール）"
      : skin === "건성"
        ? "高保湿（ヒアルロン酸・セラミド）"
        : skin === "지성"
          ? "皮脂ケア（BHA・ナイアシン）"
          : "水分・トーンバランス";
  const approachEn =
    sensitivity === "민감"
      ? "soothing ingredients (Centella, Panthenol)"
      : skin === "건성"
        ? "deep hydration (Hyaluronic acid, Ceramide)"
        : skin === "지성"
          ? "sebum care (BHA, Niacinamide)"
          : "hydration & tone balance";
  const sun = hiUV ? " + 무기자차 선크림" : "";
  const sunJp = hiUV ? " + ノンケミカル日焼け止め" : "";
  const sunEn = hiUV ? " + mineral sunscreen" : "";
  const summary = `${skinTypeForRec} + ${driver} → ${approach}${sun} → 아래 추천`;
  const summaryJp = `${skinTr.jp} + ${driverJp} → ${approachJp}${sunJp} → 下記のおすすめ`;
  const summaryEn = `${skinTr.en} + ${driverEn} → ${approachEn}${sunEn} → recommendations below`;

  return { summary, summaryJp, summaryEn, items };
}

/* ── [5-4] 소용량 샘플 로직 ── */
export const SAMPLE_TIERS = [10, 20, 30, 50, 75];
const DAILY_USAGE: Record<string, number> = { 토너: 2.0, 세럼: 1.0, 앰플: 1.0, 크림: 1.5, 선크림: 2.0, 클렌징: 2.0 };
const MOIST_CATS = ["토너", "크림", "앰플", "세럼"];

// 본품 용량(fullMl)보다 작은 샘플 티어만 유효 — 본품보다 크거나 같은 "샘플"은 의미가 없다.
export function validSampleTiers(fullMl: number) {
  return SAMPLE_TIERS.filter((t) => t < fullMl);
}

export function dailyUsage(category: string) {
  return DAILY_USAGE[category] ?? 1.5;
}

// 여행 일수 + 기후로 추천 용량 티어 산출. 샘플 티어는 본품 용량(fullMl)보다 작은
// 것만 유효하며, 필요 용량이 본품 용량 이상이면 샘플 대신 본품 구매를 추천한다(full: true).
export function recommendVolume(category: string, days: number, dryHigh: boolean, uvHigh: boolean, fullMl: number) {
  const need = dailyUsage(category) * days * 1.2;
  const validTiers = validSampleTiers(fullMl);
  if (validTiers.length === 0) {
    return { ml: 0, qty: 0, need: Math.round(need), full: true };
  }
  let idx = validTiers.findIndex((t) => t >= need);
  if (idx === -1) idx = validTiers.length - 1;
  if (dryHigh && MOIST_CATS.includes(category)) idx = Math.min(validTiers.length - 1, idx + 1);
  if (uvHigh && category === "선크림") idx = Math.min(validTiers.length - 1, idx + 1);
  const ml = validTiers[idx];
  const full = need >= fullMl;
  const qty = ml >= 75 && need > 75 && !full ? Math.ceil(need / 75) : 1;
  return { ml, qty, need: Math.round(need), full };
}

// ml당 단가 기준 소용량 금액 (100원 반올림)
export function samplePrice(price: number, fullMl: number, ml: number) {
  const per = price / fullMl;
  return Math.round((per * ml) / 100) * 100;
}
